resource "aws_cloudwatch_log_metric_filter" "route53_query_logging_filter" {
  name           = "Route53QueryLoggingFilter"
  log_group_name = aws_route53_query_log_config.example.cloudwatch_log_group_name
  pattern        = "" # Filter for all events, adjust if needed
}

resource "aws_cloudwatch_log_resource_policy" "route53_query_logging_policy" {
  name        = "route53-query-logging-policy"
  policy_document = jsonencode({
    Version   = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "route53.amazonaws.com"
        }
        Action = [
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:log-group:${aws_route53_query_log_config.example.cloudwatch_log_group_name}:*"
      }
    ]
  })
}

