provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}


resource "aws_db_instance" "primary" {
  identifier = "primary"
  allocated_storage    = 20
  engine               = "postgres"
  instance_class       = "db.t3.micro"
  username             = "dbadmin"
  password             = "your_password_here"
  skip_final_snapshot  = true
  backup_retention_period  = 7
}

resource "aws_db_instance" "replica_1" {
  replicate_source_db  = aws_db_instance.primary.identifier
  instance_class       = "db.t3.micro"
  identifier           = "mydb-replica-1"
  skip_final_snapshot  = true
}

resource "aws_db_instance" "replica_2" {
  replicate_source_db  = aws_db_instance.primary.identifier
  instance_class       = "db.t3.micro"
  identifier           = "mydb-replica-2"
  skip_final_snapshot  = true
}


# Route53 Hosted Zone
resource "aws_route53_zone" "main" {
  name = "example53.com"
}


# Route53 Records for each RDS Read Replica with a Weighted Routing Policy
resource "aws_route53_record" "replica_1_cname" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "replica1.example53.com"
  type    = "CNAME"
  records = [aws_db_instance.replica_1.endpoint]
  ttl     = "60"
  weighted_routing_policy {
    weight = 10
  }
  set_identifier = "replica-1-record"
}

resource "aws_route53_record" "replica_2_cname" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "replica2.example53.com"
  type    = "CNAME"
  records = [aws_db_instance.replica_2.endpoint]
  ttl     = "60"
  weighted_routing_policy {
    weight = 20
  }
  set_identifier = "replica-2-record"
}

response:
```hcl
resource "aws_route53_zone" "main" {
  name = "main"
}

resource "aws_route53_record" "primary" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "primary.main"
  type    = "A"
  ttl     = 300
  records = ["192.0.2.1"] #Replace with the actual IP address of the primary instance
}

resource "aws_route53_record" "replica_1" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "replica-1.main"
  type    = "A"
  ttl     = 300
  records = ["192.0.2.2"] #Replace with the actual IP address of replica 1
}

resource "aws_route53_record" "replica_2" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "replica-2.main"
  type    = "A"
  ttl     = 300
  records = ["192.0.2.3"] #Replace with the actual IP address of replica 2
}

resource "aws_route53_weighted_routing_policy" "weighted_policy" {
  record_id = aws_route53_record.primary.id

  weighted_records {
    weight = 60
    record = aws_route53_record.primary.id
  }

  weighted_records {
    weight = 20
    record = aws_route53_record.replica_1.id
  }

  weighted_records {
    weight = 20
    record = aws_route53_record.replica_2.id
  }
}
```

