      option_name = "MeasureName"
      value = "CPUUtilization"
    }
    option_settings {
      namespace = "aws:autoscaling:trigger"
      option_name = "Statistic"
      value = "Average"
    }
    option_settings {
      namespace = "aws:autoscaling:trigger"
      option_name = "LowerThreshold"
      value = "20"
    }
    option_settings {
      namespace = "aws:autoscaling:trigger"
      option_name = "UpperThreshold"
      value = "80"
    }
    option_settings {
      namespace = "aws:autoscaling:trigger"
      option_name = "Period"
      value = "60"
    }
    option_settings {
      namespace = "aws:autoscaling:trigger"
      option_name = "EvaluationPeriods"
      value = "3"
    }
    option_settings {
      namespace = "aws:autoscaling:trigger"
      option_name = "Unit"
      value = "Percent"
    }
  }
}

