terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# VPC
resource "aws_vpc" "eb_vpc" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "eb_vpc"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.eb_vpc.id
  tags = {
    Name = "eb_igw"
  }
}

# Subnets
resource "aws_subnet" "eb_subnet_public_1" {
  vpc_id     = aws_vpc.eb_vpc.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-east-1a" # Replace with your desired AZ
  map_public_ip_on_launch = true
  tags = {
    Name = "eb_subnet_public_1"
  }
}

resource "aws_subnet" "eb_subnet_public_2" {
  vpc_id     = aws_vpc.eb_vpc.id
  cidr_block = "10.0.2.0/24"
  availability_zone = "us-east-1b" # Replace with your desired AZ
  map_public_ip_on_launch = true
  tags = {
    Name = "eb_subnet_public_2"
  }
}

# Route Table
resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.eb_vpc.id
  tags = {
    Name = "public_rt"
  }
}

resource "aws_route" "internet_route" {
  route_table_id         = aws_route_table.public_rt.id
  destination_cidr_block = "0.0.0.0/0"
  gateway_id             = aws_internet_gateway.igw.id
}

resource "aws_route_table_association" "subnet_1_assoc" {
  subnet_id      = aws_subnet.eb_subnet_public_1.id
  route_table_id = aws_route_table.public_rt.id
}

resource "aws_route_table_association" "subnet_2_assoc" {
  subnet_id      = aws_subnet.eb_subnet_public_2.id
  route_table_id = aws_route_table.public_rt.id
}

# Security Group
resource "aws_security_group" "eb_env_sg" {
  name        = "eb_env_sg"
  description = "Security group for Elastic Beanstalk environments"
  vpc_id      = aws_vpc.eb_vpc.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# RDS Database
resource "aws_db_instance" "shared_rds" {
  allocated_storage    = 20
  engine               = "mysql"
  engine_version       = "8.0"  # Specify your desired MySQL version
  instance_class       = "db.t3.micro"
  name                 = "shared_rds"
  username             = "admin"
  password             = "password" # Replace with a strong password
  vpc_security_group_ids = [aws_security_group.eb_env_sg.id]
  db_subnet_group_name = aws_db_subnet_group.rds_subnet_group.name
  skip_final_snapshot  = true
}

resource "aws_db_subnet_group" "rds_subnet_group" {
  name       = "rds-subnet-group"
  subnet_ids = [aws_subnet.eb_subnet_public_1.id, aws_subnet.eb_subnet_public_2.id]
}

# Elastic Beanstalk Environments (example - you'll need to customize these)
resource "aws_elasticbeanstalk_environment" "eb_env_1" {
  application_name = "my-eb-app" # Replace with your application name
  environment_name = "my-eb-env-1"
  solution_stack_name = "64bit Amazon Linux 2 v3.5.1 running Node.js 18" #Adjust to your stack
  version_label = "v1" # Replace with your version label
  settings {
    platform_settings {
      environment_type = "SingleInstance"

      option_settings {
        namespace = "aws:elasticbeanstalk:environment"
        option_name = "EnvironmentType"
        value = "SingleInstance"
      }
    }
  }

  vpc_configuration {
    vpc_id           = aws_vpc.eb_vpc.id
    subnet_ids       = [aws_subnet.eb_subnet_public_1.id, aws_subnet.eb_subnet_public_2.id]
    security_group_ids = [aws_security_group.eb_env_sg.id]
  }
}

resource "aws_elasticbeanstalk_environment" "eb_env_2" {
  application_name = "my-eb-app" # Replace with your application name
  environment_name = "my-eb-env-2"
  solution_stack_name = "64bit Amazon Linux 2 v3.5.1 running Node.js 18" #Adjust to your stack
  version_label = "v1" # Replace with your version label
  settings {
    platform_settings {
      environment_type = "SingleInstance"
      option_settings {
        namespace = "aws:elasticbeanstalk:environment"
        option_name = "EnvironmentType"
        value = "SingleInstance"
      }
    }
  }
  vpc_configuration {
    vpc_id           = aws_vpc.eb_vpc.id
    subnet_ids       = [aws_subnet.eb_subnet_public_1.id, aws_subnet.eb_subnet_public_2.id]
    security_group_ids = [aws_security_group.eb_env_sg.id]
  }
}
