    compute_type = "BUILD_GENERAL1_SMALL"
    image        = "aws/codebuild/standard:5.0"
    type         = "LINUX_CONTAINER"

    environment_variables = [
      {
        name  = "MY_VARIABLE"
        value = "my_value"
      },
      {
        name  = "ANOTHER_VARIABLE"
        value = "another_value"
      },
    ]
  }

  artifacts {
    type = "NO_ARTIFACTS"
  }

  logs_config {
    cloudwatch_logs {
      groupname = "/aws/codebuild/${var.aws_region}/${data.aws_caller_identity.current.account_id}/codebuild-logs"
      streamname = "example-codebuild-log-stream"
    }
  }

  service_role_arn = aws_iam_role.codebuild_role.arn

  cache {
    type = "S3"
    location = "s3://your-codebuild-cache-bucket/cache" # Replace with your cache bucket details
  }
}

