  name               = "codebuild-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "codebuild.amazonaws.com"
        },
        Effect = "Allow",
        Sid    = ""
      },
    ],
  })

  inline_policy {
    name = "codebuild-policy"
    document = jsonencode({
      Version = "2012-10-17",
      Statement = [
        {
          Action = [
            "s3:GetObject",
            "s3:PutObject",
            "s3:ListBucket"
          ],
          Effect   = "Allow",
          Resource = [
            "arn:aws:s3:::your-codebuild-cache-bucket",       # Replace with your cache bucket
            "arn:aws:s3:::your-codebuild-cache-bucket/*"      # Replace with your cache bucket
          ]
        },
        {
          Effect = "Allow",
          Action = [
            "logs:CreateLogGroup",
            "logs:CreateLogStream",
            "logs:PutLogEvents"
          ],
          Resource = "arn:aws:logs:*:*:*"
        },
        {
          Effect = "Allow",
          Action = [
            "iam:PassRole"
          ],
          Resource = "*"
        }
      ]
    })
