        name  = "MY_VARIABLE"
        value = "my_value"
      },
      {
        name  = "ANOTHER_VARIABLE"
        value = "another_value"
      },
    ]
  }

  artifacts {
    type = "NO_ARTIFACTS"
  }

  logs_config {
    cloudwatch_logs {
      groupname = "/aws/codebuild/${var.aws_region}/${data.aws_caller_identity.current.account_id}/codebuild-logs"
      streamname = "example-codebuild-log-stream"
    }
  }

  service_role_arn = aws_iam_role.codebuild_role.arn

  cache {
    type = "S3"
    location = "s3://your-codebuild-cache-bucket/cache" # Replace with your cache bucket details
  }
}

data "aws_caller_identity" "current" {}

resource "aws_iam_role" "codebuild_role" {
  name               = "codebuild-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "codebuild.amazonaws.com"
        },
        Effect = "Allow",
        Sid    = ""
      },
    ],
  })

  inline_policy {
    name = "codebuild-policy"
    document = jsonencode({
      Version = "2012-10-17",
      Statement = [
        {
          Action = [
            "s3:GetObject",
            "s3:PutObject",
            "s3:ListBucket"
          ],
          Effect   = "Allow",
          Resource = [
            "arn:aws:s3:::your-codebuild-cache-bucket",       # Replace with your cache bucket
            "arn:aws:s3:::your-codebuild-cache-bucket/*"      # Replace with your cache bucket
          ]
        },
        {
          Effect = "Allow",
          Action = [
            "logs:CreateLogGroup",
            "logs:CreateLogStream",
            "logs:PutLogEvents"
          ],
          Resource = "arn:aws:logs:*:*:*"
        },
        {
          Effect = "Allow",
          Action = [
            "iam:PassRole"
          ],
          Resource = "*"
        }
      ]
    })
  }
}
