resource "aws_lex_bot" "trip_booking_bot" {
  name        = "TripBookingBot"
  description = "A chatbot for booking trips."
  idle_session_timeout_in_minutes = 5
  voice_role_arn = "arn:aws:lex:us-east-1:123456789012:role/LexVoiceRole" # Replace with a valid ARN
  clarification_prompt {
    max_attempts = 2
    prompts = [
      "Sorry, I didn't understand. Can you please rephrase?",
      "Could you please say that again?"
    ]
  }
  intents = [
    {
      name = "BookTrip"
      slots = [
        {
          name             = "Destination"
          slot_constraint   = "Required"
          slot_type        = "AMAZON.City"
          value_elicitation_prompt {
            prompts = [
              "Where would you like to travel to?"
            ]
            max_attempts = 3
          }
        },
        {
          name             = "DepartureDate"
          slot_constraint   = "Required"
          slot_type        = "AMAZON.DATE"
          value_elicitation_prompt {
            prompts = [
              "What date would you like to depart?"
            ]
            max_attempts = 3
          }
        },
        {
          name             = "ReturnDate"
          slot_constraint   = "Required"
          slot_type        = "AMAZON.DATE"
          value_elicitation_prompt {
            prompts = [
              "What date would you like to return?"
            ]
            max_attempts = 3
          }
        },
        {
          name             = "NumberOfPassengers"
          slot_constraint   = "Required"
          slot_type        = "AMAZON.NUMBER"
          value_elicitation_prompt {
            prompts = [
              "How many passengers will be travelling?"
            ]
            max_attempts = 3
          }
        }
      ]
      sample_utterances = [
        "I want to book a trip",
        "Book me a flight",
        "I need to travel to {Destination} from {DepartureDate} to {ReturnDate} for {NumberOfPassengers} people"
      ]
    }
  ]
  child_bot_alias {
    name              = "TestAlias"
    description       = "Test bot alias"
    conversation_log_settings {
      log_settings = [
        {
          destination = "CloudWatchLogs"
          log_group_name = "/aws/lex/TripBookingBot"
          log_stream_name = "TestAliasStream"
        }
      ]
    }
  }
}

