resource "aws_kinesis_firehose_delivery_stream" "redshift_stream" {
  name        = "redshift-firehose-stream"
  destination = "redshift"

  redshift_configuration {
    cluster_id            = "your_redshift_cluster_id" # Replace with your Redshift cluster ID
    user_name             = "your_redshift_user_name" # Replace with your Redshift user name
    password              = "your_redshift_password"   # Replace with your Redshift user password
    role_arn              = "arn:aws:iam::your_account_id:role/your_redshift_role" # Replace with your Redshift role ARN
    copy_options          = {
      max_error_records = 10
    }
    manifest_file_prefix = "s3://" + aws_s3_bucket.manifest_bucket.bucket + "/manifest/"
  }

  input_format_configuration {
    malformed_records_handling {
      record_format_type = "JSON"
    }

    compression_format = "GZIP"
    serializer {
      role_arn = "arn:aws:iam::your_account_id:role/your_firehose_role" # Replace with your Firehose role ARN
      logging_options {
        enabled = true
        log_destination_type = "KinesisFirehose"
        log_group_name       = "/aws/kinesis-firehose/redshift-firehose-stream"
        log_stream_name      = "redshift-firehose-stream-log"
      }
    }
  }

  tags = {
    Name        = "Redshift Firehose Stream"
    Environment = "Production"
  }
}

resource "aws_s3_bucket" "manifest_bucket" {
  bucket = "your-manifest-bucket-name" # Replace with your S3 bucket name
  acl    = "private"

  tags = {
    Name        = "Manifest Bucket"
    Environment = "Production"
  }
}
```

