    endpoint               = "https://serverless.us-east-1.es.amazonaws.com" # Replace with your OpenSearch Serverless endpoint
    index_name             = "my-opensearch-index"
    index_rotation_period = "1H"
    region                 = "us-east-1" # Replace with your OpenSearch Serverless region
    role_arn               = "arn:aws:iam::123456789012:role/KinesisFirehoseToOpenSearchRole" # Replace with your IAM role ARN
    s3_backup_mode         = "FailedRecordsOnly"
    vpc_config {
      security_group_ids = ["sg-xxxxxxxxxxxxxxxxx"] # Replace with your security group IDs
      subnet_ids         = ["subnet-xxxxxxxxxxxxxxxxx", "subnet-yyyyyyyyyyyyyyyyy"] # Replace with your subnet IDs
    }
  }

  input_format_configuration {
    records_format_configuration {
      record_format_type = "JSON"
      conversion_configuration {
        enabled = false
      }
    }
  }

  retry_limit = 3
}
```

