resource "aws_kinesisanalyticsv2_application" "example" {
  name              = "example-kinesis-analytics-app"
  runtime_environment = "JAVA_11"
  service_role_arn = "arn:aws:iam::123456789012:role/KinesisAnalyticsRole" 

  code_configuration {
    code_location {
      bucket_name = "your-code-bucket-name"
      object_key  = "your-application.zip"
    }
  }

  application_configuration {
    application_name = "example-kinesis-analytics-app"
    application_window_configuration {
      window_duration = "SECONDS(300)"
      allowed_late_arrival_time = "SECONDS(60)"
    }

    kinesis_streaming_input {
      input_name = "input_stream"
      input_configuration {
        kinesis_input_stream_configuration {
          resource_arn = "arn:aws:kinesis:us-east-1:123456789012:stream/your-kinesis-stream-name"
          record_format {
            record_format_type = "JSON"
          }
        }
      }
    }

    output {
      output_name = "output_stream"
      output_configuration {
        kinesis_stream_configuration {
          destination_stream_arn = "arn:aws:kinesis:us-east-1:123456789012:stream/your-destination-stream-name"
          record_format {
            record_format_type = "JSON"
          }
        }
      }
    }


    sql_application_configuration {
      query = "SELECT * FROM input_stream;"
    }
  }
}

