resource "aws_route53_zone" "primary" {
  name = "example.com" # Replace with your domain
}

resource "aws_route53_geo_location" "us_east" {
  continent_code = "US"
  location_code  = "US" #You can be more specific if needed (e.g. US-VA)
}

resource "aws_route53_geo_location" "eu_west" {
  continent_code = "EU"
  location_code  = "EU" #You can be more specific if needed (e.g. EU-DE)
}

resource "aws_route53_record" "geo_record" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "www.example.com" # Replace with your record name
  type    = "A"

  geo_location {
    continent_code = aws_route53_geo_location.us_east.continent_code
    location_code  = aws_route53_geo_location.us_east.location_code
    record_set_id  = "us-record"
  }

  geo_location {
    continent_code = aws_route53_geo_location.eu_west.continent_code
    location_code  = aws_route53_geo_location.eu_west.location_code
    record_set_id  = "eu-record"
  }

  ttl     = 300
  records = ["192.0.2.1", "192.0.2.2"] #Replace with US endpoint IPs
  set_identifier = "geo-routing-policy"
}

resource "aws_route53_record" "eu_record_alias" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "www.example.com" # Replace with your record name
  type    = "A"
  alias {
    name                   = "your-eu-endpoint.example.com"  #replace with your eu endpoint
    zone_id                = "Z123456789ABCDEFG"    #replace with your eu endpoint zone ID
    evaluate_target_health = false
  }

  set_identifier = "eu-record"
}

resource "aws_route53_record" "us_record_alias" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "www.example.com" # Replace with your record name
  type    = "A"
  alias {
    name                   = "your-us-endpoint.example.com"  #replace with your us endpoint
    zone_id                = "Z987654321FEDCBA"    #replace with your us endpoint zone ID
    evaluate_target_health = false
  }

  set_identifier = "us-record"
}
