  region = "us-east-1" # Replace with your desired AWS region
}

data "aws_caller_identity" "current" {}

data "aws_ecr_repository" "repository" {
  name = "your-ecr-repository-name" # Replace with your ECR repository name
}

data "aws_ecr_image" "latest_stable" {
  repository_name = data.aws_ecr_repository.repository.name
  image_tag      = "stable"
}

locals {
  image_tag    = data.aws_ecr_image.latest_stable.image_digest != null ? data.aws_ecr_image.latest_stable.image_digest : "latest"
  aws_tags = {
    Environment = "Dev"
    Terraform   = "true"
    Workspace   = "MyWorkspace" # Replace with your desired workspace name
  }
  cluster_name = "my-eks-cluster" # Replace with your desired cluster name
}

module "eks" {
  source  = "terraform-aws-modules/eks/aws"
  version = "~> 19.0"

  cluster_name    = local.cluster_name
  cluster_version = "1.27" # Specify the desired Kubernetes version

  vpc_id     = "vpc-xxxxxxxxxxxxxxxxx" # Replace with your VPC ID
  subnet_ids = ["subnet-xxxxxxxxxxxxxxxxx", "subnet-xxxxxxxxxxxxxxxxx"] # Replace with your subnet IDs

  managed_node_group_defaults = {
    instance_types = ["t3.medium"]
    desired_size   = 3
    min_size       = 2
    max_size       = 4
    labels = {
      "lifecycle.kubernetes.io/efs-mount" = "true"
    }
  }

  tags = local.aws_tags
}

output "cluster_name" {
  value = module.eks.cluster_name
}

output "cluster_endpoint" {
  value = module.eks.cluster_endpoint
}

output "cluster_certificate_authority_data" {
  value = module.eks.cluster_certificate_authority_data
  sensitive = true
}

provider "helm" {
  kubernetes {
    host                   = module.eks.cluster_endpoint
    token                  = module.eks.cluster_certificate_authority_data
    cluster_name           = module.eks.cluster_name

  }
}

provider "kubernetes" {
  host                   = module.eks.cluster_endpoint
  token                  = module.eks.cluster_certificate_authority_data
  cluster_name           = module.eks.cluster_name
}
