provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# IAM Role for EKS Fargate Pod Execution
resource "aws_iam_role" "eks_fargate_pod_execution_role" {
  name               = "eks-fargate-pod-execution-role"
  description        = "IAM role for EKS Fargate pod execution"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "eks-fargate-pods.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_policy_attachment" "eks_fargate_pod_execution_policy" {
  role       = aws_iam_role.eks_fargate_pod_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSFargatePodExecutionRolePolicy"
}

# EKS Cluster information (Replace with your actual values)
variable "cluster_name" {
  type    = string
  default = "your_eks_cluster_name"
}

variable "cluster_endpoint" {
  type = string
  default = "your_eks_cluster_endpoint"
}

variable "cluster_certificate_authority" {
  type    = string
  default = "your_eks_cluster_certificate_authority"
}

variable "cluster_security_group_id" {
  type    = string
  default = "your_cluster_security_group_id"
}

variable "subnets" {
  type    = list(string)
  default = ["subnet-xxxxxxxxxxxxx", "subnet-yyyyyyyyyyyyy"]  # Replace with your subnet IDs
}

# Tag for subnets
resource "aws_resourcegroups_group" "eks_subnet_group" {
  name        = "eks-subnets"
  resource_query {
    query = jsonencode({
      ResourceTypeFilters = ["AWS::EC2::Subnet"]
      TagFilters          = [
        {
          Key   = "kubernetes.io/cluster/${var.cluster_name}"
          Values = ["owned"]
        }
      ]
    })
  }
}


# EKS Fargate Profile
resource "aws_eks_fargate_profile" "fargate_profile" {
  cluster_name            = var.cluster_name
  fargate_profile_name    = "kube-system-fargate-profile"
  namespace               = "kube-system"
  pod_execution_role_arn = aws_iam_role.eks_fargate_pod_execution_role.arn
  subnet_ids              = var.subnets
}

# Kubernetes Provider
provider "kubernetes" {
  host                   = var.cluster_endpoint
  cluster_ca_certificate = var.cluster_certificate_authority
  token                  = data.aws_eks_cluster_auth_info.current.token
}

data "aws_eks_cluster_auth_info" "current" {
  cluster_name = var.cluster_name
}

# Patch Kubernetes Deployment 'coredns'
resource "null_resource" "patch_coredns_deployment" {
  provisioner "local-exec" {
    command = "kubectl --kubeconfig=${HOME}/.kube/config -n kube-system patch deployment coredns -p '{"spec":{"template":{"spec":{"containers":[{"name":"coredns","resources":{"limits":{"cpu":"100m","memory":"128Mi"}}}}]' " # Example patch
  }
  depends_on = [aws_eks_fargate_profile.fargate_profile]
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_subnet" "test_eks_1" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"

  availability_zone = data.aws_availability_zones.available.names[0]

  tags = {
    "kubernetes.io/cluster/test" = "shared"
  }
}

resource "aws_subnet" "test_eks_2" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.2.0/24"

  availability_zone = data.aws_availability_zones.available.names[1]

  tags = {
    "kubernetes.io/cluster/test" = "shared"
  }
}

resource "aws_iam_role" "eks-cluster" {
  name = "eks-cluster-1"

  assume_role_policy = <<POLICY
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "Service": "eks.amazonaws.com"
      },
      "Action": "sts:AssumeRole"
    }
  ]
}
POLICY
}

resource "aws_iam_role_policy_attachment" "eks_cluster_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy"
  role       = aws_iam_role.eks-cluster.name
}

resource "aws_iam_role_policy_attachment" "eks_service_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSServicePolicy"
  role       = aws_iam_role.eks-cluster.name
}


resource "aws_eks_cluster" "cluster" {
  name     = "test"
  role_arn = aws_iam_role.eks-cluster.arn

  vpc_config {
    subnet_ids = [
      aws_subnet.test_eks_1.id,
      aws_subnet.test_eks_2.id
    ]
  }

  depends_on = [
    aws_iam_role_policy_attachment.eks_cluster_policy,
    aws_iam_role_policy_attachment.eks_service_policy,
  ]
}

resource "aws_iam_role" "eks-fargate-profile" {
  name = "eks-fargate-profile"

  assume_role_policy = jsonencode({
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "eks-fargate-pods.amazonaws.com"
      }
    }]
    Version = "2012-10-17"
  })
}

resource "aws_iam_role_policy_attachment" "eks-fargate-profile" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSFargatePodExecutionRolePolicy"
  role       = aws_iam_role.eks-fargate-profile.name
}

resource "aws_eks_fargate_profile" "kube-system" {
  cluster_name           = aws_eks_cluster.cluster.name
  fargate_profile_name   = "kube-system"
  pod_execution_role_arn = aws_iam_role.eks-fargate-profile.arn

  subnet_ids = [
    aws_subnet.test_eks_1.id,
    aws_subnet.test_eks_2.id
  ]

  selector {
    namespace = "kube-system"
  }

  depends_on = [ aws_iam_role_policy_attachment.eks-fargate-profile ]
}

data "aws_eks_cluster_auth" "eks" {
  name = aws_eks_cluster.cluster.id
}

resource "null_resource" "k8s_patcher" {
  depends_on = [aws_eks_fargate_profile.kube-system]

  triggers = {
    endpoint = aws_eks_cluster.cluster.endpoint
    ca_crt   = base64decode(aws_eks_cluster.cluster.certificate_authority[0].data)
    token    = data.aws_eks_cluster_auth.eks.token
  }

  provisioner "local-exec" {
    command = <<EOH
      cat >/tmp/ca.crt <<EOF
      ${base64decode(aws_eks_cluster.cluster.certificate_authority[0].data)}
      EOF
      kubectl \n        --server="${aws_eks_cluster.cluster.endpoint}" \n        --certificate_authority=/tmp/ca.crt \n        --token="${data.aws_eks_cluster_auth.eks.token}" \n        patch deployment coredns \n        -n kube-system --type json \n        -p='[{"op": "remove", "path": "/spec/template/metadata/annotations/eks.amazonaws.com~1compute-type"}]'
      EOH
  }

  lifecycle {
    ignore_changes = [triggers]
  }
}

