resource "aws_iam_policy" "example" {
  name        = "example"
  description = "IAM policy for EKS pods"

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect   = "Allow",
        Action   = "sts:AssumeRoleWithWebIdentity",
        Resource = "*",
        Condition = {
          StringEquals = {
            "sts:ExternalProvider" = "arn:aws:iam::<ACCOUNT_ID>:oidc-provider/oidc.eks.<REGION>.amazonaws.com/id/<OIDC_PROVIDER_ID>"
          },
          StringLike = {
            "sts:Aud" = "sts.amazonaws.com"
          }
        }
      }
    ]
  })
}

resource "aws_iam_role" "example" {
  name               = "example"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "eks.amazonaws.com"
        },
        Sid = ""
      }
    ]
  })
}

resource "aws_iam_policy_attachment" "s3_readonly" {
  role       = aws_iam_role.example.name
  policy_arn = "arn:aws:iam::aws:policy/ReadOnlyAccess/S3"
}

resource "aws_eks_identity_provider" "example" {
  cluster_name       = "example"
  provider_url       = "arn:aws:iam::<ACCOUNT_ID>:oidc-provider/oidc.eks.<REGION>.amazonaws.com/id/<OIDC_PROVIDER_ID>"
}

resource "aws_eks_pod_identity_association" "example" {
  cluster_name              = aws_eks_identity_provider.example.cluster_name
  namespace                  = "default"
  service_account            = "default"
  identity_provider_arn      = aws_eks_identity_provider.example.arn
  role_arn                   = aws_iam_role.example.arn
  allowed_namespaces          = ["default"]
}

