  name        = "S3ToSNSPolicy"
  description = "Allows S3 to publish to an SNS topic"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action   = ["SNS:Publish"]
        Effect   = "Allow"
        Principal = {
          Service = "s3.amazonaws.com"
        }
        Resource = aws_sns_topic.s3_event_notification_topic.arn
        Condition = {
