  name               = "automated-snapshot"
  schedule           = "cron(0 */12 * * ? *)" # Every 12 hours
  target_action      = [
    {
      action = "Snapshot"
      parameters = {
        "SnapshotIdentifier" = "auto-snapshot-${formatdate("YYYYMMDDHHMMSS", timestamp())}"
      }
    }
  ]
  depends_on = [aws_redshift_cluster.redshift_cluster]
}

