terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# Create a VPC
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "main-vpc"
  }
}

# Create Public Subnet
resource "aws_subnet" "public_subnet" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-east-1a" # Replace with your desired Availability Zone
  map_public_ip_on_launch = true
  tags = {
    Name = "public-subnet"
  }
}

# Create Private Subnet
resource "aws_subnet" "private_subnet" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.2.0/24"
  availability_zone = "us-east-1b" # Replace with your desired Availability Zone
  tags = {
    Name = "private-subnet"
  }
}

# Create Internet Gateway
resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id
  tags = {
    Name = "main-igw"
  }
}

# Associate Internet Gateway with VPC
resource "aws_route_table" "public_route" {
  vpc_id = aws_vpc.main.id
  routes = [
    {
      cidr_block = "0.0.0.0/0"
      gateway_id = aws_internet_gateway.gw.id
    },
  ]
  tags = {
    Name = "public-route-table"
  }
}

resource "aws_route_table_association" "public_assoc" {
  subnet_id      = aws_subnet.public_subnet.id
  route_table_id = aws_route_table.public_route.id
}

# Create Launch Template
resource "aws_launch_template" "ec2_fleet_template" {
  name_prefix   = "ec2-fleet-template-"
  image_id      = "ami-0c55b954219d76a65" # Latest Amazon Linux 2 AMI - replace with current
  instance_type = "t3.micro"
  key_name      = "your_key_pair_name" # Replace with your key pair name

  network_interfaces {
    associate_public_ip_address = false
    security_groups = ["your_security_group_id"] # Replace with your security group ID
  }
}

# Create EC2 Fleet
resource "aws_ec2_fleet" "example" {
  name = "ec2-fleet-example"

  launch_template_configs {
    launch_template_spec {
      id      = aws_launch_template.ec2_fleet_template.id
      version = "$Latest"
    }

    overrides = {
      instance_type = "t3.micro"
    }
    weight = 5
  }

  launch_template_configs {
    launch_template_spec {
      id      = aws_launch_template.ec2_fleet_template.id
      version = "$Latest"
    }

    overrides = {
      instance_type = "t3.micro"
    }
    weight = 4
    spot_price = "0.05"
  }

  target_capacity_type = "ON_DEMAND_AND_SPOT"
  target_capacity = 9


}

