  name        = "msk-serverless-trigger"
  location    = "us-east1"
  display_name = "MSK Serverless Trigger"

  event_filter {
    attribute = "type.googleapis.com/google.cloud.msk.v1.Event"
  }

  destination {
    cloud_run_service = "your-cloud-run-service-name" # Replace with your Cloud Run service name
  }
}

resource "google_cloudfunctions_function" "msk_function" {
  name        = "msk-serverless-function"
  location    = "us-east1"
  description = "Serverless function triggered by MSK events"

  runtime = "python39"

  entry_point = "main"

  source {
    bucket = google_storage_bucket.msk_bucket.name
    object = "function.zip" # Upload your function code as function.zip
  }

  trigger_http = false
  trigger_event = google_eventarc_trigger.msk_trigger.name

  environment_variables = {
    PROJECT_ID = "your-gcp-project-id" # Replace with your GCP project ID
  }
}

