terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-2"
}

resource "aws_msk_cluster" "default" {
  cluster_name           = "my-serverless-msk-cluster"
  kafka_version          = "3.2"
  number_of_broker_nodes = 1

  configuration_info {
    arn      = aws_msk_configuration.default.arn
    revision = 1
  }

  encryption_info {
    encryption_at_rest_kms_key_id = "arn:aws:kms:us-east-2:123456789012:key/your-kms-key-id" # Replace with your KMS key ARN
  }

  open_monitoring {
    prometheus {
      enabled = true
    }
  }

  serverless {
    enabled = true
  }

  tags = {
    Name = "serverless-msk-cluster"
  }
}

resource "aws_msk_configuration" "default" {
  name             = "my-serverless-msk-config"
  kafka_versions   = ["3.2"]
  serverless_enabled = true
}

resource "aws_iam_role" "msk_role" {
  name = "msk-serverless-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "kafka.amazonaws.com"
        },
        Effect = "Allow",
        Sid = ""
      },
    ]
  })
}


resource "aws_msk_cluster_policy" "default" {
  cluster_name = aws_msk_cluster.default.cluster_name
  policy       = jsonencode({
    version = "2018-05-01",
    statements = [
      {
        "Effect": "Allow",
        "Principal": {
          "AWS": "*"
        },
        "Action": [
          "kafka:DescribeCluster",
          "kafka:GetBootstrapBrokers",
          "kafka:ListClusters",
          "kafka:ListTags",
          "kafka:GetCompatibleKafkaVersions"
        ],
        "Resource": "*"
      }
    ]
  })

}

