extracted_code:
resource "aws_msk_cluster" "example" {
  cluster_name           = "my-msk-cluster"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3

  configuration_info {
    arn      = aws_msk_configuration.example.arn
    revision = 1
  }

  broker_node_group_info {
    client_subnets = [
      "subnet-xxxxxxxxxxxxxxxxx",
      "subnet-yyyyyyyyyyyyyyyyy",
      "subnet-zzzzzzzzzzzzzzzzz"
    ]
    instance_type   = "kafka.m5.large"
    security_groups = [aws_security_group.msk.id]
    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  encryption_info {
    encryption_at_rest_kms_key_id = "arn:aws:kms:REGION:ACCOUNT_ID:key/YOUR_KMS_KEY_ID"
  }

  open_monitoring {
    prometheus {
      exporter {
        extra_labels = {
          cluster_name = "my-msk-cluster"
        }
      }
    }
  }

  logging_info {
    cloudwatch_logs {
      log_group_name = "my-msk-logs"
    }
    s3 {
      bucket_name = aws_s3_bucket.msk_logs.id
      prefix      = "msk-logs"
    }
    firehose {
      delivery_stream_name = aws_kinesis_firehose_delivery_stream.msk_firehose.name
    }
  }
}

resource "aws_msk_configuration" "example" {
  name             = "my-msk-config"
  kafka_versions = ["2.8.1"]

  server_properties = <<EOF
auto.create.topics.enable = true
delete.topic.enable = true
default.replication.factor = 3
min.insync.replicas = 2
EOF
}

resource "aws_s3_bucket" "msk_logs" {
  bucket = "my-msk-logs-bucket"
  acl    = "private"

  logging {
    target_bucket = "my-msk-logs-bucket"
    target_prefix = "s3-access-logs/"
  }
}

resource "aws_kinesis_firehose_delivery_stream" "msk_firehose" {
  name        = "my-msk-firehose"
  destination = "s3"

  s3_configuration {
    role_arn           = "arn:aws:iam::ACCOUNT_ID:role/FirehoseRole"
    bucket_name        = aws_s3_bucket.msk_logs.id
    prefix             = "firehose-logs/"
    buffering_hints {
      size_in_mb = 5
      interval_in_seconds = 60
    }
    compression_format = "GZIP"
  }
}

resource "aws_security_group" "msk" {
  name        = "msk-sg"
  description = "Security group for MSK cluster"

  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "TCP"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

