resource "aws_msk_configuration" "example" {
  name             = "my-msk-config"
  kafka_versions = ["2.8.1"]

  server_properties = <<EOF
auto.create.topics.enable = true
delete.topic.enable = true
default.replication.factor = 3
min.insync.replicas = 2
EOF
}

resource "aws_s3_bucket" "msk_logs" {
  bucket = "my-msk-logs-bucket"
  acl    = "private"

  logging {
    target_bucket = "my-msk-logs-bucket"
    target_prefix = "s3-access-logs/"
  }
}

resource "aws_kinesis_firehose_delivery_stream" "msk_firehose" {
  name        = "my-msk-firehose"
  destination = "s3"

  s3_configuration {
    role_arn           = "arn:aws:iam::ACCOUNT_ID:role/FirehoseRole"
    bucket_name        = aws_s3_bucket.msk_logs.id
    prefix             = "firehose-logs/"
    buffering_hints {
      size_in_mb = 5
      interval_in_seconds = 60
    }
    compression_format = "GZIP"
  }
}

resource "aws_security_group" "msk" {
  name        = "msk-sg"
  description = "Security group for MSK cluster"

  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "TCP"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}
