resource "aws_s3_bucket" "msk_s3_bucket" {
  bucket = "example-msk-bucket"
  acl    = "private"
}

resource "aws_kinesis_firehose_delivery_stream" "example" {
  name        = "example-firehose"
  destination = "s3"
  s3_destination {
    bucket        = aws_s3_bucket.msk_s3_bucket.bucket
    prefix        = "msk-data/"
    role_arn      = "arn:aws:iam::123456789012:role/KinesisFirehoseRole"
    buffering_hints {
      interval_in_seconds = 60
      size_in_mb         = 5
    }
  }
  role_arn = "arn:aws:iam::123456789012:role/KinesisFirehoseRole"
}

resource "aws_msk_connect_custom_plugin" "example" {
  name        = "debezium-plugin"
  description = "Debezium Custom Plugin"
  location {
    s3 {
      bucket  = aws_s3_bucket.msk_s3_bucket.bucket
      key     = "debezium.zip"
      version = "1.0"
    }
  }
}

resource "aws_msk_connect_connector" "example" {
  name            = "debezium-connector"
  cluster_id      = aws_msk_cluster.example.id
  connector_config = {
    "tasks.max" = "1"
    "topics" = "your-topic-name"
    "key.converter" = "org.apache.kafka.connect.storage.StringConverter"
    "value.converter" = "org.apache.kafka.connect.storage.StringConverter"
    "connector.class" = "io.debezium.connector.jdbc.JdbcSourceConnector"
    "database.hostname" = "your-db-hostname"
    "database.port" = 5432
    "database.user" = "your-db-user"
    "database.password" = "your-db-password"
    "database.server.name" = "your-db-server-name"
    "database.include.list" = "public.your_table"
    "plugin.name" = aws_msk_connect_custom_plugin.example.name
  }
}
