# Create an S3 bucket to store student code and results
resource "aws_s3_bucket" "autograder_bucket" {
  bucket = "cs-autograder-bucket-${random_id.random_id.hex}"
  acl    = "private"

  tags = {
    Name        = "CS Autograder Bucket"
    Environment = "Production"
  }
}

resource "random_id" "random_id" {
  byte_length = 8
}

# Create an IAM role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name               = "codebuild-autograder-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "codebuild.amazonaws.com"
        },
        Effect = "Allow",
        Sid    = ""
      },
    ]
  })
}

# Attach S3 access policy to CodeBuild role
resource "aws_iam_policy" "codebuild_s3_access" {
  name        = "codebuild-s3-access"
  description = "Allows CodeBuild to access S3 bucket"
  policy      = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ],
        Effect   = "Allow",
        Resource = [
          aws_s3_bucket.autograder_bucket.arn,
          "${aws_s3_bucket.autograder_bucket.arn}/*",
        ],
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_s3_attachment" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_s3_access.arn
}

