    type            = "GITHUB"
    location        = "https://github.com/<your_org>/<your_repo>" # Replace with your repo
    git_clone_depth = 10
  }

  environment {
    compute {
      type            = "BUILD_GENERAL1_SMALL"
      image           = "aws/codebuild/standard:7.0"
      memory          = 512
    }
    environment_variables = {
      # Add any necessary environment variables here
    }
  }

  artifacts {
    type = "NO_ARTIFACTS"
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/autograder-logs" # Adjust groupname
      stream_name = "autograder-stream"
    }
  }

  vpc_config {
    security_group_ids = [aws_security_group.codebuild_sg.id]
    subnets            = [aws_subnet.autograder_subnet.id]
  }
}

