terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired AWS region
}

# VPC
resource "aws_vpc" "autograder_vpc" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "Autograder VPC"
  }
}

# Subnet
resource "aws_subnet" "autograder_subnet" {
  vpc_id     = aws_vpc.autograder_vpc.id
  cidr_block = "10.0.1.0/24"
  tags = {
    Name = "Autograder Subnet"
  }
}

# Internet Gateway (not directly used for isolation, but necessary for NAT)
resource "aws_internet_gateway" "autograder_igw" {
  vpc_id = aws_vpc.autograder_vpc.id
  tags = {
    Name = "Autograder Internet Gateway"
  }
}

# NAT Gateway (to allow CodeBuild to pull dependencies, but prevent student code from reaching the internet)
resource "aws_nat_gateway" "autograder_nat" {
  subnet_id         = aws_subnet.autograder_subnet.id
  allocation_id     = aws_eip.autograder_nat_eip.id
  tags = {
    Name = "Autograder NAT Gateway"
  }
}

# Elastic IP for NAT Gateway
resource "aws_eip" "autograder_nat_eip" {
  domain = "vpc"
  tags = {
    Name = "Autograder NAT EIP"
  }
}

# Route table to route traffic from the subnet to the NAT Gateway
resource "aws_route_table" "autograder_route_table" {
  vpc_id = aws_vpc.autograder_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.autograder_nat.id
  }

  tags = {
    Name = "Autograder Route Table"
  }
}

resource "aws_route_table_association" "autograder_route_table_association" {
  subnet_id      = aws_subnet.autograder_subnet.id
  route_table_id = aws_route_table.autograder_route_table.id
}

# Security Group for CodeBuild
resource "aws_security_group" "codebuild_sg" {
  name        = "codebuild-sg"
  description = "Security group for CodeBuild"
  vpc_id      = aws_vpc.autograder_vpc.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]  # Adjust as needed for SSH access from your IP.  Consider removing for production.
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"] # Allow all outbound traffic, but student code cannot initiate outbound through NAT
  }
}

# S3 Bucket
resource "aws_s3_bucket" "autograde_results" {
  bucket = "autograde-results-${random_string.bucket_suffix.result}"
  acl    = "private"

  tags = {
    Name = "Autograder Results Bucket"
  }
}

resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

# CodeBuild Project
resource "aws_codebuild_project" "autograde_project" {
  name         = "autograde-project"
  description  = "CodeBuild project for autograding"
  service_role = aws_iam_role.codebuild_role.arn

  source {
    type      = "GITHUB"
    location  = "https://github.com/<your_org>/<your_repo>" # Replace with your GitHub repository URL
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:6.0" # Use an appropriate CodeBuild image
    type                        = "LINUX"
    privileged_mode = true # Needed for some build environments
  }

  artifacts {
    type = "NO_ARTIFACTS"
  }

  logs_config {
    cloudwatch_logs {
      group_name = "/aws/codebuild/autograde-logs"
      stream_name = "autograde-log-stream"
    }
  }

  vpc_config {
    vpc_id             = aws_vpc.autograder_vpc.id
    subnets            = [aws_subnet.autograder_subnet.id]
    security_group_ids = [aws_security_group.codebuild_sg.id]
  }
}

# IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "codebuild.amazonaws.com"
        },
        Effect = "Allow",
        Sid = ""
      },
    ],
  })
}

resource "aws_iam_policy" "codebuild_policy" {
  name        = "codebuild-policy"
  description = "Policy for CodeBuild to access S3 and logs"
  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ],
        Effect   = "Allow",
        Resource = [
          aws_s3_bucket.autograde_results.arn,
          "${aws_s3_bucket.autograde_results.arn}/*"
        ]
      },
      {
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ],
        Effect   = "Allow",
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Resource = "*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_role_policy" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_policy.arn
}

