terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# DynamoDB Table for cat picture metadata
resource "aws_dynamodb_table" "cat_pictures" {
  name             = "cat-pictures"
  billing_mode     = "PAY_PER_REQUEST"
  attribute {
    name = "picture_id"
    type = "S"
  }
  attribute {
    name = "upload_date"
    type = "S"
  }
}

# S3 Bucket for storing cat pictures
resource "aws_s3_bucket" "cat_pictures_bucket" {
  bucket = "cat-pictures-bucket-unique" # Replace with a unique bucket name
  acl    = "private"

  tags = {
    Name        = "Cat Pictures Bucket"
    Environment = "Dev"
  }
}

# IAM Role for Lambda function
resource "aws_iam_role" "lambda_role" {
  name = "lambda-cat-pictures-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "lambda.amazonaws.com"
        },
        Effect = "Allow",
        Sid    = ""
      },
    ]
  })
}

resource "aws_iam_policy" "lambda_policy" {
  name        = "lambda-cat-pictures-policy"
  description = "Policy for Lambda function to access DynamoDB and S3"

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "dynamodb:GetItem",
          "dynamodb:PutItem",
          "dynamodb:Query"
        ],
        Effect   = "Allow",
        Resource = aws_dynamodb_table.cat_pictures.arn
      },
      {
        Action = [
          "s3:GetObject",
          "s3:PutObject"
        ],
        Effect   = "Allow",
        Resource = "${aws_s3_bucket.cat_pictures_bucket.arn}/*"
      },
      {
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ],
        Effect   = "Allow",
        Resource = "arn:aws:logs:*:*:*"
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_role_policy" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = aws_iam_policy.lambda_policy.arn
}

# Lambda Function
resource "aws_lambda_function" "cat_pictures_lambda" {
  function_name = "cat-pictures-lambda"
  role          = aws_iam_role.lambda_role.arn
  runtime       = "nodejs18.x"
  handler       = "index.handler"
  timeout       = 30
  memory_size   = 128

  source_code_hash = filebase64("./lambda/cat_pictures.zip") # Replace with the path to your zipped Lambda code

  environment {
    variables = {
      DYNAMODB_TABLE = aws_dynamodb_table.cat_pictures.name
      S3_BUCKET      = aws_s3_bucket.cat_pictures_bucket.bucket
    }
  }
}

# Lambda Permission
resource "aws_lambda_permission" "api_gateway_lambda_permission" {
  function_name = aws_lambda_function.cat_pictures_lambda.name
  statement_id  = "AllowExecutionFromAPIGateway"
  action        = "lambda:InvokeFunction"
  principal     = "apigateway.amazonaws.com"
  source_arn    = aws_api_gateway_rest_api.cat_pictures_api.execution_arn
}

# API Gateway REST API
resource "aws_api_gateway_rest_api" "cat_pictures_api" {
  name = "cat-pictures-api"
}

# API Gateway Resource
resource "aws_api_gateway_resource" "cat_pictures_resource" {
  rest_api_id = aws_api_gateway_rest_api.cat_pictures_api.id
  path_part   = "catpictures"
}

# API Gateway Method (GET - random cat picture)
resource "aws_api_gateway_method" "cat_pictures_get_method" {
  rest_api_id   = aws_api_gateway_rest_api.cat_pictures_api.id
  resource_id   = aws_api_gateway_resource.cat_pictures_resource.id
  http_method   = "GET"
  authorization = "NONE"

  integration {
    type            = "AWS_PROXY"
    integration_http_method = "GET"
    uri             = aws_lambda_function.cat_pictures_lambda.invoke_arn
  }
}

# API Gateway Method (POST - upload cat picture)
resource "aws_api_gateway_method" "cat_pictures_post_method" {
  rest_api_id   = aws_api_gateway_rest_api.cat_pictures_api.id
  resource_id   = aws_api_gateway_resource.cat_pictures_resource.id
  http_method   = "POST"
  authorization = "NONE"

  integration {
    type            = "AWS_PROXY"
    integration_http_method = "POST"
    uri             = aws_lambda_function.cat_pictures_lambda.invoke_arn
  }
}

# API Gateway Deployment
resource "aws_api_gateway_deployment" "cat_pictures_deployment" {
  rest_api_id = aws_api_gateway_rest_api.cat_pictures_api.id
  stage_name  = "dev"
}

output "api_gateway_endpoint" {
