provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# Create an EC2 key pair
resource "aws_key_pair" "ec2_key_pair" {
  key_name   = "my-ec2-key"
  public_key = "ssh-rsa AAAAB3NzaC1yc2EAAAADAQABAAABAQ...your_public_key..." #Replace with your public key
}

# Create a security group that allows SSH access
resource "aws_security_group" "ec2_security_group" {
  name        = "ec2-sg"
  description = "Allow SSH inbound traffic"
  vpc_id      = "vpc-xxxxxxxxxxxxxxxxx"  # Replace with your VPC ID

  ingress {
    description = "SSH from anywhere"
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}


# Create an EC2 instance
resource "aws_instance" "ec2_instance" {
  ami                    = "ami-0c55b4418d903642b" # Replace with a suitable AMI for your region
  instance_type          = "t2.micro"
  key_name               = aws_key_pair.ec2_key_pair.key_name
  vpc_security_group_ids = [aws_security_group.ec2_security_group.id]

  tags = {
    Name = "MyEC2Instance"
  }
}

# Create a Backup vault
resource "aws_backup_vault" "backup_vault" {
  name = "my-backup-vault"
  tags = {
    Name = "MyBackupVault"
  }
}


# Create a Backup Plan
resource "aws_backup_plan" "backup_plan" {
  name = "my-backup-plan"
  rule {
    rule_name = "DailyBackupRule"
    target_backup_window {
      start_window = "00:00"
      end_window   = "01:00"
    }
    schedule {
      cron_expression = "0 0 * * ?" # Daily at midnight UTC
    }
  }
}

# Create Backup Selection – associates the EC2 instance with the backup plan
resource "aws_backup_selection" "ec2_backup_selection" {
  backup_plan_id = aws_backup_plan.backup_plan.id
  resource_selection {
    iaas {
      instance_arn = aws_instance.ec2_instance.arn
    }
  }
  tags = {
    Name = "EC2 Backup Selection"
  }
}

