provider "aws" {
  region = "us-east-1" # Replace with your preferred region
}

# S3 Bucket for storing video content
resource "aws_s3_bucket" "video_bucket" {
  bucket = "video-streaming-bucket-${random_string.random_id.hex}"
  acl    = "private"

  versioning {
    enabled = true
  }

  tags = {
    Name        = "Video Streaming Bucket"
    Environment = "Production"
  }
}

resource "random_string" "random_id" {
  length  = 4
  special = false
  upper   = false
}


# CloudFront Distribution
resource "aws_cloudfront_distribution" "video_distribution" {
  comment       = "CloudFront distribution for video streaming"
  enabled       = true
  price_class   = "UseOnlyLowerPerSecChargedRate" # Consider based on cost/performance

  default_root_object = "index.html" # Or a default video file

  origin {
    domain_name = aws_s3_bucket.video_bucket.bucket_regional_domain_name
    origin_id   = "S3Origin"

    s3_origin_config {
      bucket = aws_s3_bucket.video_bucket.bucket
    }
  }

  viewer_protocol_policy = "redirect-to-https"

  default_cache_behavior {
    target_origin_id = "S3Origin"
    viewer_protocol_policy = "redirect-to-https"
    allowed_methods  = ["GET", "HEAD"]
    cached_methods   = ["GET", "HEAD"]
    forwarded_values {
      query_string = false
      cookies      = false
    }
  }

  restriction {
    geo_restriction {
      restriction_type = "none" # Allow from all locations - customize as needed
    }
  }
}


# Route 53 Record Set
resource "aws_route53_record" "video_record" {
  zone_id = "YOUR_ROUTE53_ZONE_ID" # Replace with your Route 53 Zone ID
  name    = "videos.example.com" # Replace with your desired domain name
  type    = "A"
  ttl     = 300
  records = [cloudfront_distribution.video_distribution.domain_name]
}

# IAM Role for CloudFront to access S3 (Optional, but recommended for better security)
resource "aws_iam_role" "cloudfront_role" {
  name = "cloudfront-s3-access"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "cloudfront.amazonaws.com"
        },
        Effect = "Allow",
        Sid    = ""
      },
    ],
  })
}

resource "aws_iam_policy" "cloudfront_s3_policy" {
  name = "cloudfront-s3-policy"
  description = "Policy to allow CloudFront to access S3 bucket"

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ],
        Effect   = "Allow",
        Resource = [
          aws_s3_bucket.video_bucket.arn,
          "${aws_s3_bucket.video_bucket.arn}/*",
        ],
      },
    ],
  })
}


resource "aws_iam_role_policy_attachment" "cloudfront_s3_attachment" {
  role       = aws_iam_role.cloudfront_role.name
  policy_arn = aws_iam_policy.cloudfront_s3_policy.arn
}

