  region = "us-east-1" # Replace with your desired region
}

# Create an S3 bucket to store video content
resource "aws_s3_bucket" "video_bucket" {
  bucket = "video-streaming-bucket-${random_string(5, true, true)}"
  acl    = "private"

  versioning {
    enabled = true
  }
}

# Create an S3 bucket policy to allow CloudFront to access the bucket
resource "aws_s3_bucket_policy" "cloudfront_access" {
  bucket = aws_s3_bucket.video_bucket.id
  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Sid    = "CloudFrontAccess",
        Effect = "Allow",
        Principal = {
          AWS = "arn:aws:iam::cloudfront:user/CloudFront Origin Access Identity ${aws_cloudfront_origin_access_identity.oai.id}"
        },
        Action   = "s3:GetObject",
        Resource = "arn:aws:s3:::${aws_s3_bucket.video_bucket.bucket}/*"
      }
    ]
  })
}


# Create a CloudFront Origin Access Identity (OAI)
resource "aws_cloudfront_origin_access_identity" "oai" {
  comment = "OAI for video streaming"
}

# Create a CloudFront distribution
resource "aws_cloudfront_distribution" "video_distribution" {
  comment                 = "Video Streaming Distribution"
  default_root_object     = "index.html"
  enabled                 = true
  is_ipv6_enabled         = true
  price_class             = "UseOnlyCloudFrontPricing"

  origin {
    domain_name           = aws_s3_bucket.video_bucket.bucket_regional_domain_name
    origin_id             = "S3-Origin"
    s3_bucket_access {
      access_type = "origin-access-control"
      origin_access_control {
        name = "OAC-VideoStreaming"
        origin_type = "S3"
        signing_behavior = "always"
        signing_protocol = "sigv4"
      }
    }
  }

  default_cache_behavior {
    allowed_methods          = ["GET", "HEAD", "OPTIONS"]
    cached_methods           = ["GET", "HEAD"]
    forwarded_values {
      query_string = false
      cookies      = false
    }
    target_origin_id = "S3-Origin"
    viewer_protocol_policy = "redirect-to-https"
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }
}

# Create a Route 53 zone
resource "aws_route53_zone" "video_zone" {
  name = "videostreaming.com" # Replace with your domain name
}

# Create a Route 53 record to point to the CloudFront distribution
resource "aws_route53_record" "video_record" {
  zone_id = aws_route53_zone.video_zone.zone_id
  name    = "www.videostreaming.com" # Replace with your desired subdomain
  type    = "A"
  ttl     = "300"
  records = [aws_cloudfront_distribution.video_distribution.domain_name]
}

# Add a random string for uniqueness of the S3 bucket
