terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired AWS region
}

module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"
  version = "5.1.1"

  name = "video-streaming-vpc"
  cidr = "10.0.0.0/16"

  azs             = ["us-east-1a", "us-east-1b", "us-east-1c"] # Replace with your desired AZs
  private_subnets = ["10.0.1.0/24", "10.0.2.0/24", "10.0.3.0/24"]
  public_subnets  = ["10.0.4.0/24", "10.0.5.0/24", "10.0.6.0/24"]

  enable_nat_gateway = true
  single_nat_gateway = true
}

resource "aws_internet_gateway" "gw" {
  vpc_id = module.vpc.vpc_id
}

resource "aws_route_table" "public" {
  vpc_id = module.vpc.vpc_id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }
}

resource "aws_route_table_association" "public_assoc" {
  subnet_id      = element(module.vpc.public_subnets, 0)
  route_table_id = aws_route_table.public.id
}

resource "aws_security_group" "lb_sg" {
  name        = "lb_sg"
  description = "Allow inbound traffic to the load balancer"
  vpc_id      = module.vpc.vpc_id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_lb" "video_lb" {
  name               = "video-streaming-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb_sg.id]
  subnets            = module.vpc.public_subnets

  enable_deletion_protection = false

  access_logs {
    s3_bucket = "your-s3-bucket-for-logs"  # Replace with your S3 bucket name
    prefix    = "video-lb-logs"
  }
}

resource "aws_lb_target_group" "video_tg" {
  name     = "video-streaming-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = module.vpc.vpc_id
  health_check {
    path     = "/"
    protocol = "HTTP"
    interval = 30
    timeout  = 5
    healthy_threshold = 2
    unhealthy_threshold = 2
  }
}

resource "aws_lb_listener" "video_listener" {
  load_balancer_arn = aws_lb.video_lb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.video_tg.arn
  }
}

resource "aws_instance" "video_server" {
  count         = 3 # Number of servers
  ami           = "ami-0c55b2ab366694241" # Replace with your desired AMI
  instance_type = "t2.micro" # Replace with your desired instance type
  subnet_id     = element(module.vpc.private_subnets, count.index)
  vpc_security_group_ids = [aws_security_group.lb_sg.id]
  key_name = "your-key-pair" # Replace with your key pair name

  tags = {
    Name = "VideoServer-${count.index + 1}"
  }
}

resource "aws_lb_target_group_attachment" "video_tg_attachment" {
  count            = length(aws_instance.video_server)
  target_group_arn = aws_lb_target_group.video_tg.arn
  target_id        = aws_instance.video_server[count.index].id
  port             = 80
}

resource "aws_route53_record" "video_record" {
  zone_id = "your-zone-id" # Replace with your hosted zone ID
  name    = "video.example.com" # Replace with your desired domain name
  type    = "A"
  ttl     = "300"
  records = [aws_lb.video_lb.dns_name]
}

