    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired AWS region
}

# VPC Module
module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"
  version = "5.0.0"

  name = "video-streaming-vpc"
  cidr = "10.0.0.0/16"

  azs             = ["us-east-1a", "us-east-1b", "us-east-1c"] # Replace with your desired AZs
  private_subnets = ["10.0.1.0/24", "10.0.2.0/24", "10.0.3.0/24"]
  public_subnets  = ["10.0.4.0/24", "10.0.5.0/24", "10.0.6.0/24"]

  enable_nat_gateway = true
  single_nat_gateway = true
}

# Security Group for EC2 Instances
resource "aws_security_group" "ec2_sg" {
  name        = "ec2-security-group"
  description = "Allow inbound traffic for video streaming servers"
  vpc_id      = module.vpc.vpc_id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
      from_port   = 22
      to_port     = 22
      protocol    = "tcp"
      cidr_blocks = ["0.0.0.0/0"] #Restrict this to your IP address in a production environment.
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "ec2-security-group"
  }
}

# Launch Template for EC2 Instances
resource "aws_launch_template" "ec2_launch_template" {
  name_prefix   = "video-streaming-lt-"
  image_id      = "ami-0c55b2ab2812c5866" # Replace with your desired AMI
  instance_type = "t2.micro"
  key_name      = "your_key_pair" # Replace with your key pair name

  network_interfaces {
    security_groups = [aws_security_group.ec2_sg.id]
    associate_public_ip_address = false
  }

  tag_specifications {
    resource_type = "instance"
    tags = {
      Name = "video-streaming-server"
    }
  }
}

# Target Group
resource "aws_lb_target_group" "video_target_group" {
  name     = "video-target-group"
  port     = 80
  protocol = "HTTP"
  vpc_id   = module.vpc.vpc_id

  health_check {
    path     = "/"
    protocol = "HTTP"
    interval = 30
    timeout  = 5
    healthy_threshold = 2
    unhealthy_threshold = 2
  }
}

# Load Balancer
resource "aws_lb" "video_lb" {
  name               = "video-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [] # Associate with appropriate security groups for LB

  subnets = module.vpc.public_subnets

  enable_deletion_protection = false

  tags = {
    Name = "video-lb"
  }
}

# Listener
resource "aws_lb_listener" "video_listener" {
  load_balancer_arn = aws_lb.video_lb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.video_target_group.arn
  }
}

# EC2 Instances
resource "aws_autoscaling_group" "video_asg" {
  name                      = "video-asg"
  desired_capacity         = 2
  max_size                 = 5
  min_size                 = 2
  vpc_zone_identifier      = module.vpc.private_subnets
  launch_template {
    id      = aws_launch_template.ec2_launch_template.id
    version = "$Latest"
  }

  target_group_arns = [aws_lb_target_group.video_target_group.arn]

  tag {
    key                 = "Name"
    value               = "video-streaming-server"
    propagate_at_launch = true
  }
}

# Route53 Zone
resource "aws_route53_zone" "video_zone" {
  name = "example.com" # Replace with your domain name
}

# Route53 Record
resource "aws_route53_record" "video_record" {
  zone_id = aws_route53_zone.video_zone.zone_id
  name    = "video.example.com" # Replace with your subdomain
  type    = "A"
  ttl     = "300"
  records = [aws_lb.video_lb.dns_name]
}

