extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# VPC
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "rds-vpc"
  }
}

# Subnets
resource "aws_subnet" "private_subnet_a" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-east-1a" # Replace with your desired availability zone
  tags = {
    Name = "rds-private-subnet-a"
  }
}

resource "aws_subnet" "private_subnet_b" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.2.0/24"
  availability_zone = "us-east-1b" # Replace with your desired availability zone
  tags = {
    Name = "rds-private-subnet-b"
  }
}

# Security Group
resource "aws_security_group" "rds_sg" {
  vpc_id      = aws_vpc.main.id
  name        = "rds-security-group"
  description = "Allow traffic to RDS instance"

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Adjust cidr block as necessary
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# IAM Role for RDS
resource "aws_iam_role" "rds_role" {
  name               = "rds-role"
  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "Service": "rds.amazonaws.com"
      },
      "Action": "sts:AssumeRole"
    }
  ]
}
EOF
}

# RDS Aurora MySQL Cluster
resource "aws_rds_cluster" "default" {
  cluster_identifier      = "aurora-mysql-cluster"
  engine                  = "aurora-mysql"
  engine_mode             = "serverless"
  engine_version          = "5.7"
  database_name           = "mydb"
  master_username         = "admin"
  master_password         = "ReplaceWithStrongPassword!" # Store in Secrets Manager in production
  db_subnet_group_name    = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  backup_retention_period = 5
  preferred_backup_window = "07:00-09:00"

  scaling_configuration {
    auto_pause               = true
    min_capacity             = 1
    max_capacity             = 2
    seconds_until_auto_pause = 300
  }
}

# DB Subnet Group
resource "aws_db_subnet_group" "default" {
  name       = "rds-db-subnet-group"
  subnet_ids = [aws_subnet.private_subnet_a.id, aws_subnet.private_subnet_b.id]
  tags = {
    Name = "RDS DB Subnet Group"
  }
}

# RDS Aurora MySQL Instance
resource "aws_rds_cluster_instance" "cluster_instance" {
  cluster_identifier = aws_rds_cluster.default.id
  instance_class     = "db.r5.large" # Adjust instance class as needed
  engine             = "aurora-mysql"
  engine_version     = "5.7"
  publicly_accessible = false
}

# AWS Secrets Manager
resource "aws_secretsmanager_secret" "rds_credentials" {
  name = "rds-credentials"

  rotation_configuration {
    rotate_immediately = false
    rotation_lambda_arn = "" # Optionally, use a Lambda for automatic rotation
  }
}

resource "aws_secretsmanager_secret_version" "rds_credentials_version" {
  secret_id     = aws_secretsmanager_secret.rds_credentials.id
  secret_string = jsonencode({
    username = "admin",
    password = "ReplaceWithStrongPassword!" # Replace with a strong password
  })
}

