  instance_name = aws_lightsail_instance.postgres_instance.name
  name = "final-postgres-snapshot"

  lifecycle {
    ignore_changes = [tags]
  }

  depends_on = [
    aws_lightsail_instance.postgres_instance
  ]
}

# Configure snapshot creation on instance deletion.  Lightsail does not have a direct
# way to create a snapshot *on* deletion from Terraform.  This creates a snapshot when
# the Terraform configuration is destroyed.  Note: you could also use a lifecycle hook
# within the instance resource itself, but snapshots are better.

