  }
}

resource "aws_s3_bucket_notification" "glacier_notification" {
  bucket = aws_s3_bucket.glacier_bucket.id

  topic_configuration {
    topic_arn = "arn:aws:sns:YOUR_REGION:YOUR_ACCOUNT_ID:glacier-retrieval-topic" # Replace with your SNS topic ARN
    event_type = "ObjectRestored:Completed"
  }

  filter_prefix = ""
  filter_suffix = ""
}

resource "aws_sns_topic" "glacier_retrieval_topic" {
  name = "glacier-retrieval-topic"

  tags = {
    Name = "Glacier Retrieval Notification Topic"
  }
}

resource "aws_s3_bucket_policy" "glacier_policy" {
  bucket = aws_s3_bucket.glacier_bucket.id
  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Sid       = "AllowS3GlacierNotifications"
        Effect    = "Allow"
        Principal = {
          Service = "s3.amazonaws.com"
        }
        Action   = "s3:PutObject"
        Resource = "arn:aws:s3:::${aws_s3_bucket.glacier_bucket.bucket}/*"
      },
    ]
  })
}
