  vpc_id = aws_vpc.main.id
  tags = {
    Name = "main-acl"
  }

  ingress {
    cidr_block = "0.0.0.0/0"
    protocol   = "tcp"
    port_range = "80"
    description = "Allow inbound HTTP"
  }

  ingress {
    cidr_block = "0.0.0.0/0"
    protocol   = "tcp"
    port_range = "443"
    description = "Allow inbound HTTPS"
  }

  egress {
    cidr_block = "0.0.0.0/0"
    protocol   = "tcp"
    port_range = "80"
    description = "Allow outbound HTTP"
  }

  egress {
    cidr_block = "0.0.0.0/0"
    protocol   = "tcp"
    port_range = "443"
    description = "Allow outbound HTTPS"
  }
}
```
